window.SHARED_NORMA_HP = {"version": "2026-05-21 · Decreto 9/2024 · Hospitalización Psiquiátrica · selección AS · +UHCIP infraestructura 2026-06-10", "fuente": "Decreto 9 / 2024 · MINSAL · Reglamento sobre Hospitalización Psiquiátrica (BCN) · Guía de Diseño para Establecimientos de Mediana Complejidad · UHCIP (MINSAL, nov. 2019), pp. 12-14 · Materiales, mobiliario e instalaciones · Modelo de Gestión UHCIP Res. N°417-16 (MINSAL 2016)", "total_secciones": 8, "total_ambitos": 76, "total_requisitos": 178, "secciones": [{"id": "establecimiento", "name": "Requisitos del Establecimiento y Autorización Sanitaria", "ambitos": [{"id": "hp_establecimiento__art85", "tipo": "ARTÍCULO", "name": "Artículo 85 · Del establecimiento o unidad", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 85, "text": "En los establecimientos de salud o unidades psiquiátricas específicas de atención cerrada para la hospitalización de personas con enfermedad o trastorno mental, se podrá realizar una hospitalización psiquiátrica en régimen completo. Lo anterior se aplicará a las unidades psiquiátricas ubicadas en los centros penitenciarios y en los centros privativos de libertad del Servicio Nacional de Menores o el Servicio Nacional de Reinserción Social Juvenil, así como aquellas destinadas al tratamiento de personas con trastornos por consumo de alcohol y otras drogas en régimen de hospitalización completa.", "notes": []}], "observaciones_general": ""}, {"id": "hp_establecimiento__art86__header", "tipo": "ARTÍCULO", "name": "Artículo 86 · De la solicitud de autorización sanitaria", "notes_in_title": [], "objetivo": "La solicitud de autorización sanitaria para la instalación y funcionamiento de establecimientos de salud o unidades psiquiátricas, públicas y privadas, donde se realice hospitalización psiquiátrica, se presentará ante la Secretaría Regional Ministerial de Salud en cuyo territorio se encuentre emplazado el establecimiento de salud o unidad psiquiátrica correspondiente. La solicitud deberá incorporar los siguientes antecedentes:", "notes_in_objetivo": [], "requisitos": [{"n": "86.a", "text": "Individualización del solicitante o de su representante legal si se tratare de una persona jurídica. En este último caso, se deberá adjuntar la documentación que respalde su representación.", "notes": []}, {"n": "86.b", "text": "Identificación del establecimiento, incluyendo nombre, correo electrónico, teléfono y dirección.", "notes": []}, {"n": "86.c", "text": "Plano o croquis a escala del establecimiento o unidad, que incluya cada una de sus áreas. Por cada sala de hospitalización se deberá indicar la distribución de camas.", "notes": []}, {"n": "86.d", "text": "Identificación del(la) director(a) técnico(a) responsable de la unidad, con copia de su certificado de título y carta de aceptación del cargo.", "notes": []}, {"n": "86.e", "text": "Planta del personal con que funcionará el establecimiento o unidad. La solicitud a la que alude este artículo deberá ser presentada junto con el comprobante de pago o recaudación del arancel de acciones de protección de la salud para su aplicación por las Secretarías Regionales Ministeriales de Salud, aprobado mediante una resolución dictada por el Ministerio de Salud.", "notes": []}], "observaciones_general": ""}, {"id": "hp_establecimiento__art87__header", "tipo": "ARTÍCULO", "name": "Artículo 87 · De los requisitos para obtener la autorización sanitaria", "notes_in_title": [], "objetivo": "Además de lo dispuesto en el decreto supremo N° 58, de 2009, del Ministerio de Salud, que aprueba las Normas Técnicas Básicas para la obtención de autorización sanitaria de los establecimientos asistenciales, o aquel que lo reemplace, se deberá cumplir con lo siguiente:", "notes_in_objetivo": [], "requisitos": [{"n": "87.a", "text": "La sala de hospitalización podrá ser individual o compartida.", "notes": []}, {"n": "87.b", "text": "Debe contar con al menos una sala de cuidados especiales de uso individual.", "notes": []}, {"n": "87.c", "text": "Debe contar con una estación de enfermería que tenga visualización directa al área de las habitaciones de los usuarios hospitalizados.", "notes": []}, {"n": "87.d", "text": "Debe contar con acceso oportuno a un laboratorio clínico y centro de imágenes para los usuarios hospitalizados.", "notes": []}, {"n": "87.e", "text": "Debe disponer de área de comedores que permita a las personas en hospitalización psiquiátrica compartir los horarios de comida.", "notes": []}, {"n": "87.f", "text": "Debe disponer de espacios destinados a recreación y esparcimiento.", "notes": []}, {"n": "87.g", "text": "Debe disponer de mecanismos de comunicación telefónica y medios digitales a los que las personas en hospitalización psiquiátrica puedan tener acceso.", "notes": []}, {"n": "87.h", "text": "Debe disponer de mecanismos de información actualizada sobre fecha y hora, noticias y otros antecedentes o medios que permitan a las personas en hospitalización psiquiátrica mantener y acrecentar el grado de ubicación en su entorno ambiental, social y cultural. Esta información deberá ser adecuada para personas con algún tipo de discapacidad o para quienes practiquen otra lengua que les impida la comprensión.", "notes": []}, {"n": "87.i", "text": "Debe contar con acceso oportuno a servicios de urgencias para los usuarios hospitalizados las veinticuatro horas del día, los siete días de la semana.", "notes": []}, {"n": "87.j", "text": "Debe disponer de baños destinados exclusivamente para los usuarios, los cuales deben tener duchas con grifería antivandálica.", "notes": []}, {"n": "87.k", "text": "Debe contar con un Director técnico, quien debe ser un médico cirujano con especialidad en psiquiatría, y que cumpla al menos media jornada en días hábiles. 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 19/22", "notes": []}, {"n": "87.l", "text": "Debe tener a disposición un médico cirujano con especialidad en psiquiatría, para prestar atención en modalidad presencial durante la jornada diurna en días hábiles, para la atención de usuarios hospitalizados.", "notes": []}, {"n": "87.m", "text": "Debe tener disponibilidad de atención médica las veinticuatro horas del día, los siete días de la semana, tanto en días hábiles como inhábiles, dentro del establecimiento.", "notes": []}, {"n": "87.n", "text": "Debe tener durante la jornada diurna un equipo profesional interdisciplinario.", "notes": []}, {"n": "87.o", "text": "Debe disponer de profesionales de enfermería que presten sus servicios las veinticuatro horas del día, los siete días de la semana, tanto en días hábiles como inhábiles.", "notes": []}, {"n": "87.p", "text": "Debe disponer de técnicos de enfermería que presten servicios las veinticuatro horas del día, los siete días de la semana, tanto en días hábiles como inhábiles.", "notes": []}], "observaciones_general": ""}, {"id": "hp_establecimiento__art88", "tipo": "ARTÍCULO", "name": "Artículo 88 · De la complementación de antecedentes", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 88, "text": "En caso de que, durante el análisis de la solicitud, la Secretaría Regional Ministerial de Salud respectiva requiera una complementación de los antecedentes, a la luz de lo dispuesto en los artículos 86 y 87 precedentes, formulará observaciones y otorgará un plazo de siete días para que éstas sean subsanadas. Con todo, si han transcurrido más de treinta días hábiles desde el vencimiento del plazo establecido en el inciso anterior, la Secretaría Regional Ministerial de Salud le advertirá al solicitante que, si no efectúa las diligencias de su cargo en el plazo de siete días contados desde este segundo requerimiento, declarará el abandono de ese procedimiento. Sin perjuicio de lo anterior, el solicitante siempre podrá desistirse de su solicitud, caso en el cual se le devolverá el arancel pagado. La Secretaría Regional Ministerial de Salud podrá realizar una o más visitas inspectivas para verificar el cumplimiento de los requisitos del artículo 87 del presente reglamento, así como la veracidad de la documentación acompañada a la solicitud.", "notes": []}], "observaciones_general": ""}, {"id": "hp_establecimiento__art89", "tipo": "ARTÍCULO", "name": "Artículo 89 · De la resolución de autorización sanitaria", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 89, "text": "La resolución de autorización sanitaria será otorgada por la Secretaría Regional Ministerial de Salud competente. Este deberá pronunciarse otorgando o rechazando la solicitud en el plazo de treinta días hábiles, contados desde la fecha en que el requirente ha completado los antecedentes exigidos para su otorgamiento y, en caso de denegarla, deberá hacerlo mediante resolución fundada. Transcurrido dicho plazo, si la autoridad no ha emitido un pronunciamiento, el establecimiento podrá exigir la autorización a través de los recursos que la ley confiere. No obstante, el establecimiento no podrá iniciar sus actividades sin la autorización expresa requerida. La autorización será válida por un periodo de cinco años. Esta podrá ser renovada por períodos iguales y sucesivos mientras no se haya dejado expresamente sin efecto. Dentro de los seis meses anteriores al vencimiento de dicho plazo, el director del establecimiento comunicará esta circunstancia a la autoridad sanitaria. Cualquier modificación de los elementos, circunstancias o antecedentes que se hayan proporcionado a la Secretaría Regional Ministerial de Salud para obtener la autorización sanitaria deberá ser comunicada a la autoridad sanitaria.", "notes": []}], "observaciones_general": ""}, {"id": "hp_establecimiento__art90__header", "tipo": "ARTÍCULO", "name": "Artículo 90 · De la modificación de autorización sanitaria", "notes_in_title": [], "objetivo": "La autorización sanitaria de funcionamiento podrá ser modificada por la Secretaría Regional Ministerial de Salud respectiva, previa solicitud del titular o representante legal del establecimiento o unidad, en los plazos y casos que se indican a continuación:", "notes_in_objetivo": [], "requisitos": [{"n": "90.a", "text": "Cambio de director técnico. El interesado, previo al cambio del director presentará la solicitud de modificación, debiendo acompañar los documentos que respalden el cumplimiento de lo estipulado en el artículo 87 letra", "notes": []}, {"n": "90.k", "text": "y el artículo 91 del presente reglamento. En el caso de que no pueda realizar dicha solicitud de manera previa, contará con un plazo de máximo cinco días hábiles desde que se realizó el cambio.", "notes": []}, {"n": "90.b", "text": "Cambio de propietario del establecimiento. El interesado, previo al cambio del propietario presentará la solicitud de modificación, debiendo acompañar los documentos que respalden esta situación. En el caso de que no pueda realizar dicha solicitud de manera previa, contará con un plazo de máximo cinco días hábiles desde que se realizó el cambio.", "notes": []}, {"n": "90.c", "text": "Cambios en la planta física que alteren el funcionamiento del establecimiento o unidad. El interesado, previamente a realizar el cambio, deberá presentar su solicitud de modificación de la planta física, debiendo acompañar el plano de la modificación propuesta. La Secretaría Regional Ministerial de Salud respectiva resolverá sobre la modificación de la autorización sanitaria mediante resolución fundada, dentro del plazo de treinta días hábiles contados desde la recepción de la solicitud y de los antecedentes requeridos. En el caso de que el titular decida el cierre transitorio o definitivo del Establecimiento, deberá dar aviso a la Secretaría Regional Ministerial de Salud respectiva, con treinta días hábiles de anticipación, para que disponga la suspensión o término de la autorización sanitaria, según corresponda.", "notes": []}], "observaciones_general": ""}, {"id": "hp_establecimiento__art91", "tipo": "ARTÍCULO", "name": "Artículo 91 · De la dirección técnica", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 91, "text": "La dirección técnica de los establecimientos de salud que realizan hospitalización psiquiátrica estará a cargo de un médico especializado en psiquiatría. 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 20/22 La dirección técnica será responsable de la organización y funcionamiento del establecimiento, así como de las actividades técnicas y administrativas que se desarrollen en él. La o el director técnico deberá designar un responsable que lo o la reemplace cuando no se encuentre presente en la unidad.", "notes": []}], "observaciones_general": ""}, {"id": "hp_establecimiento__art92", "tipo": "ARTÍCULO", "name": "Artículo 92 · De la acreditación", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 92, "text": "Los establecimientos públicos y privados donde se realice hospitalización psiquiátrica deberán cumplir las exigencias específicas dispuestas por el Ministerio de Salud para la acreditación de dichos establecimientos, servicios o unidades.", "notes": []}], "observaciones_general": ""}, {"id": "hp_establecimiento__art93", "tipo": "ARTÍCULO", "name": "Artículo 93 · Del comité de ética", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 93, "text": "Los establecimientos que otorguen prestaciones psiquiátricas en la modalidad de atención cerrada deberán contar con un comité de ética, conforme a lo establecido en el artículo 20 de la ley N° 20.584.", "notes": []}], "observaciones_general": ""}, {"id": "hp_establecimiento__art94", "tipo": "ARTÍCULO", "name": "Artículo 94 · De los establecimientos psiquiátricos asilares", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 94, "text": "Prohíbase la creación de nuevos establecimientos psiquiátricos asilares y de atención segregada en salud mental. Sólo se permitirá la hospitalización psiquiátrica transitoria, de personas en los establecimientos psiquiátricos asilares y de atención segregada en salud mental existentes al 11 de mayo del 2021 y que cumplan con los requisitos establecidos en el Título VI de este reglamento.", "notes": []}], "observaciones_general": ""}]}, {"id": "derechos-operacion", "name": "Derechos y Operación Clínica del Establecimiento", "ambitos": [{"id": "hp_derechos-operacion__art6__header", "tipo": "ARTÍCULO", "name": "Artículo 6 · De la capacidad de consentir", "notes_in_title": [], "objetivo": "Por regla general, se considerará que las personas susceptibles de hospitalización psiquiátrica señaladas en el inciso primero del artículo 5 precedente, son capaces de consentir respecto de cualquier tipo de procedimiento o tratamiento vinculado a su atención de salud, incluyendo de esta forma la hospitalización psiquiátrica, los tratamientos que en dicho contexto se ofrezcan y otras prestaciones ambulatorias de atención de salud mental y psiquiatría, en igualdad de condiciones que el resto de la población. Desde el primer ingreso de la persona a un servicio de atención en salud mental, será obligación del establecimiento integrarla a un plan de consentimiento libre e informado, como parte de un proceso permanente de acceso a información para la toma de decisiones en salud mental, en conformidad con lo dispuesto en el artículo 4 de la ley N° 21.331. Con el objeto de resguardar el derecho a ejercer el consentimiento libre e informado, al momento de la hospitalización, la persona y el profesional de salud del equipo tratante responsable del ingreso, firmarán un documento de consentimiento sobre su hospitalización psiquiátrica, así como también, de planes de intervención en casos de crisis psicoemocional, y de otras herramientas de resguardo, con la finalidad de hacer primar la voluntad y preferencia de la persona en el evento de afecciones futuras y graves a su capacidad mental, que impidan manifestar su consentimiento, el cual deberá ser elaborado por el Ministerio de Salud. Lo anterior, no obsta a que el plan de tratamiento deberá ser elaborado por la persona en conjunto con el equipo interdisciplinario, y que el proceso de consentimiento se prolongare durante la hospitalización y no se limite a un acto único. Si es requerida la evaluación de la capacidad de consentir en el momento de la hospitalización, ésta se realizará de acuerdo con la legislación y con las normativas vigentes emitidas por el Ministerio de Salud. La evaluación de la capacidad de consentir será siempre específica a una determinada decisión establecida de manera clara y válida sólo para el momento específico en que es realizada y no será generalizable a otros tratamientos o a otros aspectos y momentos de la vida de la persona. Será deber de los equipos tratantes realizar las acciones de apoyo y ajustes razonables necesarios para facilitar la comprensión de la persona en el proceso de consentimiento, incluidos acceso a intérprete lingüístico y de señas, material de lectura fácil y otros que resulten pertinentes. Si la evaluación realizada, determina que por motivos clínicos la persona no se encuentra con la capacidad de consentir, salvo que se encuentre en el supuesto que establece el literal", "notes_in_objetivo": [], "requisitos": [{"n": "6.b", "text": "del artículo 15 de la ley N° 20.584, ya sea al ingreso o durante la hospitalización psiquiátrica, se entenderá que la hospitalización es de carácter involuntaria siempre que se cumplan, además, los requisitos establecidos en el artículo 13 de la ley N° 21.331 y del artículo 40 de este reglamento. Tratándose de niños, niñas y adolescentes menores de edad, la determinación del consentimiento se atendrá a lo expresado en el artículo 79 de este reglamento.", "notes": []}], "observaciones_general": ""}, {"id": "hp_derechos-operacion__art11__header", "tipo": "ARTÍCULO", "name": "Artículo 11 · Del informe al término de la hospitalización", "notes_in_title": [], "objetivo": "Toda persona tendrá derecho a recibir por parte del o la médica tratante, un informe legible una vez finalizada su hospitalización psiquiátrica, de acuerdo a lo dispuesto en el artículo 11 de la ley N° 20.584. Este informe deberá contener a lo menos:", "notes_in_objetivo": [], "requisitos": [{"n": "11.a", "text": "La identificación de la persona y de él o la profesional que actuó como tratante principal.", "notes": []}, {"n": "11.b", "text": "El período de tratamiento, con fecha de ingreso y egreso.", "notes": []}, {"n": "11.c", "text": "Una información comprensible acerca del diagnóstico de ingreso y de alta, con sus respectivas fechas, su evolución clínica y los resultados más relevantes de exámenes y procedimientos efectuados que sean pertinentes al diagnóstico e indicaciones a seguir.", "notes": []}, {"n": "11.d", "text": "Una lista de los medicamentos y dosis suministrados durante el tratamiento y de aquellos prescritos al alta.", "notes": []}, {"n": "11.e", "text": "Otras intervenciones o indicaciones no farmacológicas.", "notes": []}, {"n": "11.f", "text": "La modalidad de atención en que se efectuará el seguimiento del tratamiento de salud, con relación a la atención recibida, en caso de ser necesario.", "notes": []}, {"n": "11.g", "text": "Nombre del establecimiento al cual está siendo derivado, si procediese.", "notes": []}], "observaciones_general": ""}, {"id": "hp_derechos-operacion__art12", "tipo": "ARTÍCULO", "name": "Artículo 12 · De la continuidad de cuidados", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 12, "text": "La hospitalización psiquiátrica debe ocurrir en un proceso de continuidad de cuidados, durante el cual se debe asegurar que la persona hospitalizada tenga la posibilidad de continuar su atención en salud mental en otro tipo de establecimiento una vez que ha sido dado de alta, de acuerdo a sus necesidades de tratamiento, recuperación y de apoyo para una efectiva inclusión social. Conforme a lo anterior, el equipo tratante, junto con las indicaciones al alta, indicará si corresponde, por medio de una derivación asistida, el establecimiento de salud o unidad psiquiátrica para la continuidad del tratamiento. Se deberá dar continuidad al tratamiento farmacológico hasta que se haga efectiva la derivación. Cuando un paciente cambie de establecimiento o unidad, podrá autorizar por escrito al nuevo equipo tratante para requerir directamente su historial clínico. Si la persona no se encuentra en condiciones de otorgar dicha autorización, igualmente podrá requerirla el equipo tratante. Con el objetivo de fortalecer su inclusión social, y sólo si ello es consentido por la persona, especialmente en los casos de niños, niñas y adolescentes, se deberá velar por la oportuna incorporación de familiares y otras personas significativas que puedan dar asistencia especial o participen del proceso de recuperación. 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 4/22", "notes": []}], "observaciones_general": ""}, {"id": "hp_derechos-operacion__art13__header", "tipo": "ARTÍCULO", "name": "Artículo 13 · Del manejo de conductas perturbadoras o agresivas en la hospitalización psiquiátrica", "notes_in_title": [], "objetivo": "Las conductas perturbadoras o agresivas son acciones de carácter físico o psicológico de manipulación del medio, que pueden llegar a ser violentas, de niveles variables de intensidad y peligrosidad, que una persona ejerce sobre sí misma, sobre otras personas, animales o cosas, en forma predecible o impredecible, provocando un daño o perturbación en su ambiente social, las que deben ser evaluadas por el equipo tratante conforme a un criterio técnico que considere su condición clínica y el contexto social que pueda estar incidiendo en ellas. Para configurar el carácter agresivo o perturbador del comportamiento, deberán considerarse tanto las condiciones personales como las circunstancias ambientales, que en la actualidad o en el pasado determinaron la conducta perturbadora o agresiva. De conformidad con lo establecido en el artículo 21 de la ley N° 21.331, el manejo de conductas perturbadoras o agresivas que pongan a la persona en condiciones de riesgo real e inminente y que amenacen la integridad o la vida de sí misma o terceros debe hacerse con estricto respeto a los derechos humanos, incorporando estrategias y protocolos para prevenir su ocurrencia, y considerando la voluntad y preferencias expresadas por la persona para el manejo de las mismas, pudiendo sólo aplicarse en los casos en que concurra indicación terapéutica acreditada por un médico, siempre que no exista otra alternativa menos restrictiva y que la necesidad de su aplicación fuere proporcional en relación a la conducta perturbadora. Los procedimientos realizados por un equipo de salud sobre una persona que presenta una conducta perturbadora o agresiva pueden ser: 1. Procedimientos de carácter no restrictivos, cuya finalidad es desescalar la conducta perturbadora o agresiva. Estos procedimientos son:", "notes_in_objetivo": [], "requisitos": [{"n": "13.a", "text": "Contención Emocional: Procedimiento que tiene como objetivo tranquilizar y estimular la confianza por medio de la comunicación verbal y el acompañamiento del equipo tratante.", "notes": []}, {"n": "13.b", "text": "Contención Ambiental: Procedimiento que consiste en el cambio espacial de la persona en crisis, de modo de reducir los estímulos perturbadores, infundir confianza y promover la realización de actividades alternativas que tiene como objetivo aplacar la crisis de pérdida de autocontrol. 2. Procedimientos de carácter restrictivo, cuya finalidad es controlar la conducta de riesgo sobre sí mismo o terceras personas. Sólo aplicarán en los casos en que hayan sido impracticables o infructuosos los procedimientos de carácter no restrictivo. Estos procedimientos son:", "notes": []}, {"n": "13.a", "text": "Contención Farmacológica: Procedimiento clínico que contempla administrar un medicamento a la persona con el objetivo de calmar y controlar la conducta de riesgo. Este procedimiento podrá ser administrado como alternativa o complemento al procedimiento de contención física o mecánica. La indicación de esta medida, el fármaco, vía de administración y dosis, es siempre responsabilidad del o la médico tratante residente o de urgencia, debiendo éste dejar registro en la ficha clínica de la indicación, especificando las condiciones por las que se indica. Toda vez que sea posible, se preferirá la vía oral de administración. La duración del tratamiento deberá ser lo más breve posible. Durante y después de la aplicación de la contención farmacológica, la persona deberá estar en constante observación por personal de enfermería.", "notes": []}, {"n": "13.b", "text": "Contención Física: Procedimiento restrictivo que consiste en la limitación y/o privación del movimiento de una parte o de todo el cuerpo, utilizando técnicas de sujeción manual.", "notes": []}, {"n": "13.c", "text": "Contención Mecánica: Procedimiento restrictivo que consiste en la limitación y/o privación del movimiento de una parte o de todo el cuerpo, utilizando técnicas de sujeción manual y elementos mecánicos, cuyo objetivo es garantizar la seguridad del paciente, de quienes le rodean y de su entorno.", "notes": []}, {"n": "13.d", "text": "Observación continua en sala individual: Procedimiento restrictivo que consiste en mantener a solas a la persona en una habitación acondicionada para ello, restringiendo sus movimientos y actividades a dicho espacio mientras persista la conducta perturbadora de riesgo o hasta la indicación del médico tratante. Durante este procedimiento se debe mantener una observación y supervisión terapéutica frecuente. Constituye una medida de último recurso a utilizar cuando otras alternativas han sido insuficientes. Los equipos tratantes deben acompañar a las personas durante estas situaciones, sobre la base de una contención emocional y ambiental. En caso de utilizar la contención física, mecánica, farmacológica y de observación continua en sala individual, éstas sólo podrán aplicarse en los casos en que concurra indicación terapéutica acreditada por un médico, y durante el tiempo estrictamente necesario, empleando todos los medios para minimizar sus efectos nocivos en la integridad física y psíquica del o la paciente. En ningún caso las acciones de contención pueden significar torturas, apremios ilegítimos u otros tratos crueles, inhumanos o degradantes. Durante el empleo de las mismas, la persona tendrá garantizada la supervisión médica permanente, en los términos que establezca la norma técnica a la que refiere el inciso final de este artículo. De todo lo actuado en el uso de estas medidas se dejará registro en la ficha clínica, se informará a la autoridad sanitaria, a la Comisión Regional de Protección de los Derechos de las Personas con Enfermedades Mentales y a un pariente o representante de la persona. De la aplicación de estas medidas y de aquellas que restrinjan temporalmente la comunicación o contacto con las visitas se podrá solicitar su revisión a la Comisión Regional de Protección de los Derechos de las Personas con Enfermedades Mentales que corresponda. En el caso de las personas hospitalizadas de forma involuntaria, estas medidas también se pondrán en conocimiento del Tribunal de Familia competente para efectos de lo establecido en el artículo 14 de la ley N° 21.331 y en el artículo 83 de este reglamento. Mediante una norma técnica expedida por el Ministerio de Salud se establecerán los requisitos y condiciones de implementación de los procedimientos 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 5/22 para el manejo de conductas perturbadoras o agresivas en salud mental.", "notes": []}], "observaciones_general": ""}, {"id": "hp_derechos-operacion__art15", "tipo": "ARTÍCULO", "name": "Artículo 15 · De la información", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 15, "text": "Toda persona que es sujeto de una hospitalización psiquiátrica tiene derecho tanto en el traslado clínico como en la hospitalización, a ser informado sobre el propósito y finalidad de ésta y su posible duración, los nombres de los miembros del equipo de salud que están participando del procedimiento y el nombre del establecimiento de salud donde será trasladado o donde se encuentra. Los equipos tratantes deberán entregar información suficiente, continua y en lenguaje comprensible para la persona, teniendo en cuenta su singularidad biopsicosocial y cultural, sobre los beneficios, riesgos y posibles efectos adversos asociados, a corto, mediano y largo plazo, en las alternativas terapéuticas propuestas, así como el derecho a no aceptarlas o a cambiar su decisión durante el tratamiento, con las limitaciones establecidas en el artículo 16 de la ley N° 20.584. La persona que es sujeto de una hospitalización psiquiátrica tendrá derecho a realizar al equipo tratante preguntas sobre el procedimiento, a recibir la información requerida en lenguaje claro, comprensible y de acuerdo con su capacidad de entendimiento, incluido el conocimiento de las resoluciones judiciales o administrativas que se hubieren dictado en torno a su hospitalización, y a ser informado de los mecanismos para estar en contacto con su familia o personas cercanas. Esta información debe ser provista con las adecuaciones requeridas atendiendo a la situación particular de cada persona, especialmente de aquellas pertenecientes a grupos de especial protección, tales como niños, niñas y adolescentes, personas migrantes, personas con discapacidad, población indígena, entre otras. Asimismo, se le debe informar respecto a eventuales procedimientos a utilizar en caso de no encontrarse en condiciones de consentir y en que se deba resguardar su integridad física y mental o la de terceros.", "notes": []}], "observaciones_general": ""}, {"id": "hp_derechos-operacion__art17__header", "tipo": "ARTÍCULO", "name": "Artículo 17 · De la declaración de voluntad anticipada", "notes_in_title": [], "objetivo": "Al iniciar un tratamiento de salud mental o en cualquier momento del desarrollo de éste, la persona podrá suscribir ante la o el Director del establecimiento, su equivalente, o la persona que este delegue, una declaración de voluntad anticipada que contendrá sus decisiones de carácter vital para el evento en que la persona no pueda expresar su voluntad o preferencias. En esta declaración se podrá manifestar el consentimiento o rechazo a determinados tratamientos médicos y decisiones relativas a su salud, las que en todo caso tendrán como límite lo dispuesto en el artículo 16 de la ley N° 20.584. Estas decisiones deberán ser respetadas por el equipo de salud tratante. Esta declaración tendrá al menos el siguiente contenido:", "notes_in_objetivo": [], "requisitos": [{"n": "17.a", "text": "Individualización de la persona que la suscribe.", "notes": []}, {"n": "17.b", "text": "Individualización de la o el Director del establecimiento u otro ante quien se realice la declaración conforme al inciso primero.", "notes": []}, {"n": "17.c", "text": "Médico tratante que certifique la capacidad suficiente, sea o no temporal, para emitir la declaración.", "notes": []}, {"n": "17.d", "text": "Instrucciones sobre el proceder frente a decisiones de carácter vital.", "notes": []}, {"n": "17.e", "text": "Indicación de los medios de apoyo utilizados en el proceso de manifestación de voluntad. 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 6/22", "notes": []}, {"n": "17.f", "text": "Firma de las personas indicadas en los literales a),", "notes": []}, {"n": "17.b", "text": "y", "notes": []}, {"n": "17.c", "text": "precedentes. En el caso de que la persona que reciba el tratamiento de salud mental no pudiera firmar, bastará con su huella digital. El Ministerio de Salud proveerá de un formulario tipo para la manifestación de voluntades anticipadas en atenciones de salud mental y entregará lineamientos a los equipos de salud para su utilización. No obstante, valdrán como tales los textos escritos que se hayan dictado cumpliendo los requisitos expresados precedentemente.", "notes": []}], "observaciones_general": ""}, {"id": "hp_derechos-operacion__art18", "tipo": "ARTÍCULO", "name": "Artículo 18 · De la confidencialidad y privacidad", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 18, "text": "Toda persona durante su hospitalización psiquiátrica tendrá derecho a que se resguarde su seguridad personal, la confidencialidad de su estadía y tratamiento dentro del establecimiento de salud o unidad psiquiátrica en que se lleve a cabo la hospitalización psiquiátrica, y a mantener el ejercicio de su vida privada, en cuanto sea compatible con su plan de tratamiento. El uso de sistemas de vigilancia electrónica o de otro tipo, al interior de los recintos de hospitalización psiquiátrica deberá ser ponderado conforme a las necesidades individuales de las personas hospitalizadas, acorde a su plan de tratamiento, resguardando el respeto de su intimidad. El uso de sistemas de vigilancia en áreas privadas deberá ser registrado en la ficha clínica, fundamentando la necesidad de dicha medida, en virtud de riesgos específicos, y sólo mientras resulte necesario y con conocimiento de la persona. Sólo el director técnico del establecimiento o unidad, o en su defecto la o el médico tratante, podrán otorgar certificados acerca de la permanencia de la persona, la naturaleza de su enfermedad o cualquier otra información relacionada con su hospitalización. Tal información sólo podrá ser extendida a petición expresa de la persona y/o a las demás personas e instituciones que se señalan en el artículo 134 del Código Sanitario y en el artículo 13 de la ley N° 20.584. Lo anterior no obsta el flujo de información útil y necesaria para el cumplimiento de las labores otorgadas en la ley N° 21.331, la ley N° 20.584 y el presente reglamento, a la autoridad sanitaria, al Tribunal de Familia competente, a la Comisión Regional de Protección de los Derechos de las Personas con Enfermedades Mentales, así como a todo otro órgano respecto del que la ley haya establecido competencia en la materia. De conformidad con las disposiciones establecidas en la ley N° 19.628, sobre protección a la vida privada, los mecanismos de comunicación de la información de carácter sensible deberán realizarse en un soporte que asegure la confidencialidad, integridad, resiliencia, seguridad en el acceso y transmisión de la información. Todas las personas que entren en contacto con los datos personales a que se refiere este reglamento, tanto en organismos públicos como privados, están obligadas a guardar secreto sobre los mismos, obligación que no cesa por haber terminado sus actividades en ese campo.", "notes": []}], "observaciones_general": ""}, {"id": "hp_derechos-operacion__art20", "tipo": "ARTÍCULO", "name": "Artículo 20 · De los derechos patrimoniales de las personas sometidas a hospitalización psiquiátrica", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 20, "text": "Toda persona en hospitalización psiquiátrica, voluntaria o involuntaria, en establecimientos de salud de atención cerrada, sean públicos o privados, mantiene la capacidad de ejercicio de sus derechos personales y patrimoniales, en consecuencia, le serán respetados los derechos que en el orden patrimonial le son inherentes, de conformidad con lo establecido en los artículos 1445 y 1446 del Código Civil, salvo que una resolución judicial disponga lo contrario. Respecto de aquellas personas en que se ha evaluado la necesidad específica de contar con apoyos y ajustes razonables para el manejo de sus bienes, éstos se otorgarán por medio de la red de apoyo social con la que cuente. En caso de no contar con la referida red de apoyo, corresponderá a la o el Director del hospital, ejercer la curaduría provisoria de los bienes de las personas hospitalizadas que carecieren de un curador o no estén sometidas a patria potestad, mientras permanezcan internados o no se les designe curador de acuerdo a las normas del derecho común, de acuerdo con lo establecido en el artículo 133 del Código Sanitario. Las personas en hospitalización psiquiátrica sujetas a la curaduría provisoria ejercida por la o el Director del establecimiento tendrán derecho a que los recursos económicos de que disponen, sean invertidos en la satisfacción de su bienestar. La determinación de la priorización de las necesidades personales se debe hacer en virtud del principio de la voluntad y preferencia de cada una de las personas. El establecimiento que está realizando la hospitalización psiquiátrica deberá proveer de los mecanismos adecuados para el apoyo del ejercicio de su autonomía de forma graduada en virtud de la intensidad de necesidades de apoyo de cada una de las personas, de acuerdo con los mecanismos que se encuentran consignados en el artículo 4 de la ley N° 21.331 y en la ley N° 20.422 que establece normas sobre igualdad de oportunidades e inclusión social de personas con discapacidad. Las personas en hospitalización psiquiátrica tendrán derecho a recibir una contraprestación pecuniaria por su participación en actividades realizadas en el marco de las terapias, que impliquen producción de objetos, obras o servicios que sean comercializados. 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 7/22 No se podrá disponer de bienes personales de la persona en hospitalización psiquiátrica para satisfacer necesidades de terceras personas, ni para solventar aspectos del funcionamiento institucional, salvo en lo que corresponda descontar como pago de los aranceles en la atención de salud mental, si procede. Las infracciones en que se incurra en la administración generarán las responsabilidades administrativas, civiles y penales que en derecho correspondan.", "notes": []}], "observaciones_general": ""}, {"id": "hp_derechos-operacion__art22", "tipo": "ARTÍCULO", "name": "Artículo 22 · Otros derechos personales", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 22, "text": "Durante la hospitalización psiquiátrica las personas podrán ejercer sus derechos ciudadanos, participar en la definición de rutinas diarias, acceder a una libertad de movimientos y comunicación con el exterior compatible con el tratamiento programado, obtener asesorías de orden legal o económico y el apoyo espiritual que requieran de los ministros de los credos religiosos que profesen, si procede, sin perjuicio de las limitaciones que se establezcan en otras leyes.", "notes": []}], "observaciones_general": ""}]}, {"id": "involuntaria", "name": "Hospitalización Involuntaria · Obligaciones del Establecimiento", "ambitos": [{"id": "hp_involuntaria__art46", "tipo": "ARTÍCULO", "name": "Artículo 46 · De la información de la hospitalización psiquiátrica involuntaria", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 46, "text": "Cuando se ejecute una hospitalización psiquiátrica involuntaria el equipo de salud respectivo deberá informar a la autoridad sanitaria competente y a algún pariente o representante de la persona, conforme lo señala el numeral 6 del artículo 40 precedente. Para informar a la autoridad sanitaria, se utilizará la plataforma de información en línea que el Ministerio de Salud disponga para este propósito. Para informar a los parientes o representantes de las personas se utilizarán los datos de contacto obtenidos, en el siguiente orden de prelación: 1) Se le consultará a la persona que ha sido hospitalizada involuntariamente los datos del pariente, persona cercana o representante legal, si corresponde, al que quiere que se le informe. 2) Si no estuviere en condiciones de otorgarlos, se le informará a la persona cuyos datos se hubieren consignado en el establecimiento como contacto de emergencia, si corresponde. Se podrá buscar información en registros clínicos de atenciones precedentes si se cuenta con ellos. En caso de que no pueda ser conocida la identidad de la persona, se coordinará con el Servicio de Registro Civil e Identificación para obtenerla. En caso de tratarse de una persona migrante sin identificación se solicitará la entrega de Rol Único Nacional provisorio para su registro, de acuerdo con lo señalado en el artículo 44 de la ley N° 21.325, que establece la ley de migración y extranjería. Tanto en los casos de personas de identidad desconocida o personas migrantes sin identificación, se intentará establecer la conexión con redes de apoyo familiares o programas sociales pertinentes. Para otorgar la información a parientes o representantes de las personas, se preferirá la comunicación telefónica. La que se realizará al menos en tres ocasiones durante el mismo día y de no tener éxito se repetirá al menos otras tres veces en días y horarios distintos, dejando siempre registro de estas gestiones en la ficha clínica. 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 11/22", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art47", "tipo": "ARTÍCULO", "name": "Artículo 47 · Del rol de la autoridad sanitaria", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 47, "text": "La Secretaría Regional Ministerial de Salud respectiva revisará y resolverá sobre la pertinencia de las solicitudes de hospitalización psiquiátrica involuntaria, propuestas por la red de salud ambulatoria, constatando el cumplimiento de los requisitos establecidos en el artículo 13 de la ley N° 21.331 y en el artículo 40 de este reglamento. En el caso de personas para las que se solicita una hospitalización involuntaria en una región distinta a la que reside, la Secretaría Regional Ministerial de Salud de la región de origen solicitará que se dicte la resolución pertinente a la autoridad sanitaria de la región donde se llevará a efecto la hospitalización, conforme a los requisitos establecidos en el inciso anterior. Le corresponderá a la autoridad sanitaria revisar las solicitudes de hospitalización involuntaria que devienen de hospitalizaciones voluntarias y comunicar al Tribunal de Familia sobre las hospitalizaciones voluntarias cuya estadía excedan de treinta días corridos. Transcurridas setenta y dos horas desde el inicio de la hospitalización psiquiátrica involuntaria, si se mantienen todas las condiciones que la hicieron procedente y se estima necesario prolongarla, la autoridad sanitaria solicitará su revisión al Tribunal de Familia competente del lugar donde se encuentre la persona hospitalizada, entregando al Tribunal todos los antecedentes que le permitan analizar el caso, debiendo incluir un informe del equipo de salud tratante que justifique la prolongación de la hospitalización psiquiátrica involuntaria. La Secretaría Regional Ministerial de Salud respectiva tendrá la responsabilidad de mantener un registro de las solicitudes de hospitalizaciones involuntarias y de aquellas que se han efectuado, en la plataforma de información en línea que el Ministerio de Salud disponga para este propósito. Igualmente, recibirá las resoluciones que ordenen la hospitalización psiquiátrica emitidas por los Tribunales de Familia.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art48", "tipo": "ARTÍCULO", "name": "Artículo 48 · De la comunicación con la autoridad sanitaria", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 48, "text": "Las comunicaciones acerca de una hospitalización psiquiátrica involuntaria, que se realicen entre equipos clínicos ambulatorios, de urgencia y de hospitalización psiquiátrica; la Secretaría Regional Ministerial de Salud respectiva; y, las Comisiones Regionales de Protección de los Derechos de las Personas con Enfermedades Mentales, se realizarán a través de la plataforma de información en línea que el Ministerio de Salud disponga para ello.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art53__header", "tipo": "ARTÍCULO", "name": "Artículo 53 · Del plazo para el inicio de una hospitalización psiquiátrica involuntaria administrativa", "notes_in_title": [], "objetivo": "Las hospitalizaciones psiquiátricas involuntarias administrativas deberán iniciarse en un plazo máximo de treinta días corridos desde que se tramitó la resolución que se señala en el literal", "notes_in_objetivo": [], "requisitos": [{"n": "53.a", "text": "del inciso segundo, del artículo 58 del presente reglamento. En caso de que la hospitalización no inicie dentro del plazo indicado precedentemente, el establecimiento requirente deberá indicar a la Secretaría Regional Ministerial de Salud competente, si es necesario o no, renovar la resolución indicada en el inciso anterior. 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 12/22 Sólo será pertinente renovar la resolución, en caso de que persistan todos los requisitos del artículo 13 de la ley N° 21.331 y del artículo 40 de este reglamento. Para ello, se deberá enviar a la Secretaría Regional Ministerial de Salud competente un informe actualizado que incluya dichos antecedentes. La resolución indicada en el inciso primero de este artículo mantendrá su vigencia por 30 días, salvo que se haya indicado que es necesaria su renovación por el establecimiento requirente. Si, tras cumplirse el plazo de treinta días indicado en el inciso precedente, aún está pendiente el pronunciamiento de la Secretaría Regional Ministerial de Salud respectiva sobre la renovación de la resolución del literal", "notes": []}, {"n": "53.a", "text": "del inciso segundo del artículo 58 del presente reglamento, se prorrogará la vigencia de la anterior, por un plazo máximo de cinco días para dictar el acto administrativo. En caso de renovarse la resolución señalada en el inciso primero de este artículo, ésta también tendrá una vigencia de treinta días corridos contados desde su tramitación. La resolución podrá renovarse hasta una vez más, conforme a lo establecido en los incisos anteriores. Si después de haberse realizado las renovaciones señaladas en el inciso precedente, la hospitalización psiquiátrica involuntaria aún no se ha llevado a cabo y sigue siendo necesaria, ésta se deberá solicitar nuevamente. En todos los casos, se considerará no ejecutada aquella resolución de hospitalización psiquiátrica involuntaria administrativa en que el médico tratante rechaza el ingreso involuntario antes del trámite de ingreso o después de este, pero antes de que la persona pernocte en el establecimiento de salud o unidad psiquiátrica, por no cumplirse actualmente las condiciones del artículo 13 de la ley N° 21.331 y del artículo 40 del presente reglamento. Esta situación deberá ser informada a la autoridad sanitaria y la resolución deberá ser dejada sin efecto.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art54__header", "tipo": "ARTÍCULO", "name": "Artículo 54 · De la evaluación e información a la autoridad sanitaria en la hospitalización psiquiátrica involuntaria", "notes_in_title": [], "objetivo": "La hospitalización involuntaria, ya sea de urgencia o administrativa, deberá ser informada de manera inmediata por el médico a la autoridad sanitaria, en un plazo máximo de veinticuatro horas desde su inicio, utilizando la plataforma en línea disponible para estos fines. En forma previa al cumplimiento de las setenta y dos horas contadas desde el ingreso a hospitalización involuntaria, ya sea de urgencia o administrativa, la o el médico y un segundo profesional clínico deberán evaluar el progreso de la persona en hospitalización psiquiátrica involuntaria y podrán proceder de la siguiente manera:", "notes_in_objetivo": [], "requisitos": [{"n": "54.a", "text": "Inicio de hospitalización voluntaria, si se cumplen los requisitos de los artículos 23 y 24 precedentes.", "notes": []}, {"n": "54.b", "text": "Alta médica voluntaria, ofreciendo tratamiento ambulatorio porque cumple con los requisitos clínicos para continuar de esta manera.", "notes": []}, {"n": "54.c", "text": "Alta voluntaria administrativa, en caso de que, aun persistiendo un grado de perturbación psicológica y/o conducta riesgosa para sí o para terceros similar al que motivó su ingreso, existe una solicitud y compromiso de familiares y/o red de apoyo de favorecer su cuidado y tratamiento ambulatorio.", "notes": []}, {"n": "54.d", "text": "Continuar la hospitalización en forma involuntaria, dado que se mantienen los requisitos establecidos en el artículo 13 de la ley N° 21.331 y en el artículo 40 del presente reglamento. En caso de proceder conforme a los literales", "notes": []}, {"n": "54.c", "text": "y d), el equipo de salud deberá informar de manera inmediata a la autoridad sanitaria, proporcionando los antecedentes recabados hasta ese momento de aquellos requeridos por el artículo 13 de la ley N° 21.331 y el artículo 40 del presente reglamento. Una vez cumplidas las setenta y dos horas desde el inicio de la hospitalización involuntaria, de acuerdo con el artículo 83 de este reglamento, la autoridad sanitaria deberá informar al Tribunal de Familia y solicitar la revisión de la medida. Se podrán incluir dentro de los antecedentes, informes de solicitud de familiar, vecino o vecina, miembro de la comunidad u otro solicitante, si los hubiere, en el que se detallen los riesgos para sí mismo o para terceros verificados en los últimos treinta días.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art59", "tipo": "ARTÍCULO", "name": "Artículo 59 · De los establecimientos de salud en los que puede llevarse a cabo una hospitalización involuntaria", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 59, "text": "De conformidad al artículo 13 de la ley N° 21.331, la hospitalización psiquiátrica involuntaria deberá realizarse en unidades de hospitalización destinadas al tratamiento intensivo de personas con enfermedades mentales. En el caso de hospitalizaciones involuntarias de urgencia, las personas podrán permanecer transitoriamente en servicios no psiquiátricos, con el apoyo de un psiquiatra u otros profesionales de salud, mientras se resuelve su traslado a una unidad de hospitalización psiquiátrica.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art60", "tipo": "ARTÍCULO", "name": "Artículo 60 · De las derivaciones", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 60, "text": "La hospitalización psiquiátrica involuntaria deberá realizarse en establecimientos de salud o unidades psiquiátricas, destinadas al tratamiento intensivo de personas con enfermedades mentales, conforme lo establecido en el Título VI de este reglamento. En el caso que no existan unidades de hospitalización especializadas en el territorio correspondiente al domicilio del paciente, éste podrá ser derivado a otro establecimiento hospitalario más cercano a su domicilio dentro de la red pública de salud, siempre que dicho establecimiento cuente con la disponibilidad para realizar el tratamiento intensivo. En caso de no existir disponibilidad en la red pública de salud, la hospitalización psiquiátrica involuntaria se realizará en un establecimiento de salud o unidad psiquiátrica de la red privada de salud en convenio que cumplan con las características señaladas en el inciso primero precedente.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art61__header", "tipo": "ARTÍCULO", "name": "Artículo 61 · De los traslados", "notes_in_title": [], "objetivo": "Si para efectuar una hospitalización psiquiátrica involuntaria que cuente con la resolución señalada en el literal", "notes_in_objetivo": [], "requisitos": [{"n": "61.a", "text": "del inciso segundo, del artículo 58 de este reglamento fuera necesario trasladar a la persona con asistencia del personal sanitario, se coordinará dentro del Servicio de Salud correspondiente u otro Servicio de Salud de la misma región. En caso de no haber disponibilidad en la región, el Servicio de Salud coordinará con su homólogo en otra región e informará a la Secretaría Regional Ministerial de Salud dónde se llevará a cabo la hospitalización. Siempre se preferirá la plaza más cercana al domicilio declarado o conocido de la persona en una hospitalización psiquiátrica involuntaria. Los traslados de personas privadas de libertad por orden judicial serán de responsabilidad de Gendarmería de Chile, de acuerdo con lo establecido en el artículo 3, letra", "notes": []}, {"n": "61.e", "text": "N° 2, del decreto ley N° 2.859, de 1979, del Ministerio de Justicia, que fija la ley orgánica de Gendarmería de Chile.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art62", "tipo": "ARTÍCULO", "name": "Artículo 62 · Del uso de medidas de contención en el traslado", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 62, "text": "Durante el procedimiento de traslado, se emplearán medidas de contención de manera excepcional, únicamente cuando exista una condición de riesgo real e inminente que amenace la integridad de la persona o de terceros, y solo para efectos de ser conducido por personal de salud al establecimiento de salud o unidad de hospitalización psiquiátrica en la que ésta se ejecutará. 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 14/22 El uso de medidas de contención, en caso de ser necesario, se aplicarán de forma gradual, de conformidad al artículo 13 de este reglamento y a la normativa vigente sobre el manejo de conductas perturbadoras o agresivas dictada por el Ministerio de Salud. El traslado siempre será un procedimiento clínico. No obstante, se podrá solicitar el auxilio de la fuerza pública, el cual deberá ser proporcionado de manera oportuna cuando lo solicite la autoridad sanitaria, de conformidad a lo establecido en el artículo 8° del Código Sanitario.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art64", "tipo": "ARTÍCULO", "name": "Artículo 64 · Del aviso a los Tribunales de Familia competentes", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 64, "text": "En los casos en que con ocasión de un traslado se altere la competencia del Tribunal de Familia que estuviere conociendo de una hospitalización psiquiátrica involuntaria, la Secretaría Regional Ministerial de Salud de origen dará aviso del traslado al Tribunal de Familia que está conociendo del caso. Por su parte, la Secretaría Regional Ministerial de Salud en cuyo territorio se encuentra el establecimiento que recibirá a la persona en hospitalización psiquiátrica involuntaria, remitirá el informe del artículo 13 de la ley N° 21.331 y el artículo 40 de este reglamento al nuevo Tribunal de Familia competente.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art66", "tipo": "ARTÍCULO", "name": "Artículo 66 · De la revisión periódica", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 66, "text": "La hospitalización psiquiátrica involuntaria no se deberá aplicar más allá del tiempo estrictamente necesario a tal propósito. Durante la hospitalización psiquiátrica involuntaria, el médico y el equipo tratante deberán evaluar semanalmente si persisten las condiciones que hicieron necesaria la hospitalización. Si las condiciones que motivaron la hospitalización psiquiátrica involuntaria persisten después de treinta días corridos desde la última revisión por parte del Tribunal de Familia correspondiente, el equipo médico e interdisciplinario deberá notificar al Tribunal conforme a lo establecido en el artículo 83 de este reglamento, si consideran necesario prolongar la hospitalización. En caso de que se determine necesaria la prórroga de la hospitalización psiquiátrica, esta no podrá exceder de treinta días corridos. Sin embargo, siempre que se mantengan los requisitos establecidos en el artículo 13 de la ley N° 21.331 y el artículo 40 de este reglamento, se podrá extender sucesivamente y hasta por el mismo periodo. Con todo, si en cualquier momento de la hospitalización psiquiátrica involuntaria se detecta que falta cualquiera de los requisitos establecidos en el artículo 13 de la ley N° 21.331 y el artículo 40 de este reglamento, se deberá proceder conforme a lo establecido en el párrafo sexto del Título III de este reglamento.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art67", "tipo": "ARTÍCULO", "name": "Artículo 67 · Del plan de tratamiento y el consentimiento", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 67, "text": "El tratamiento deberá estar basado en un plan individual, prescrito por un equipo multidisciplinario, que atienda las necesidades de salud de la persona. Este plan deberá ser la alternativa terapéutica menos restrictiva entre las disponibles y deberá considerar la identidad y expresión de género, situación migratoria, pertenencia a algún pueblo originario o situación de discapacidad de la persona. El plan se revisará periódicamente y se modificará en caso de ser necesario. Durante la hospitalización psiquiátrica involuntaria, la persona tendrá derecho a expresar su voluntad o preferencias y participar activamente en la elaboración y revisión de su plan de tratamiento, en la medida que sus capacidades psíquicas o intelectuales se lo permitan. Los equipos clínicos tratantes deberán prestar los apoyos necesarios para obtener el consentimiento o preferencias de las personas y realizar esfuerzos para acercar lo máximo posible el tratamiento prescrito durante la hospitalización psiquiátrica involuntaria a dicha voluntad. Asimismo, deberán mantener 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 15/22 una comunicación regular con la red de apoyo de la persona, favoreciendo el contacto en el marco del plan de tratamiento.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art71", "tipo": "ARTÍCULO", "name": "Artículo 71 · Del alta médica u hospitalaria", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 71, "text": "En el caso de la hospitalización psiquiátrica involuntaria, el alta médica u hospitalaria, tal como se define en el artículo 10 de este reglamento, es una facultad del equipo de salud. Una vez que cese la situación de riesgo cierto e inminente para la persona o terceros, el equipo de salud deberá ofrecer al paciente la opción de continuar su hospitalización de forma voluntaria o darle el alta hospitalaria. La restauración plena de la condición de salud no es necesaria para el término de la hospitalización psiquiátrica involuntaria. Se debe cautelar que al egreso se optimicen los procedimientos de derivación asistida para garantizar del mejor modo posible la continuidad de cuidados. En los casos en que se haya dictado una resolución administrativa por la procedencia de la hospitalización psiquiátrica involuntaria, la Secretaría Regional Ministerial de Salud correspondiente deberá dictar la resolución que le pone término a la misma, incluso si la persona ha sido hospitalizada en un establecimiento privado.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art72", "tipo": "ARTÍCULO", "name": "Artículo 72 · Del abandono", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 72, "text": "Se considerará abandono del establecimiento de salud o unidad de hospitalización psiquiátrica, lo dispuesto en el inciso primero del artículo 34 precedente. Una vez que sea detectado el abandono, se dará aviso a la autoridad sanitaria, al Tribunal de Familia que revisó la hospitalización psiquiátrica involuntaria y al pariente o representante de la persona, conforme a lo señalado en el artículo 34 del reglamento. De no haber ubicado a un pariente o representante de la persona al momento de la hospitalización se reintentará el proceso del señalado artículo. Asimismo, se informará al equipo de salud mental referente del caso en la atención ambulatoria. De acuerdo con la información recabada, se evaluará la pertinencia de revincular a la persona para continuar la hospitalización, o bien proceder al alta hospitalaria.", "notes": []}], "observaciones_general": ""}, {"id": "hp_involuntaria__art73", "tipo": "ARTÍCULO", "name": "Artículo 73 · De la reanudación de la hospitalización", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 73, "text": "En caso de reanudarse la hospitalización psiquiátrica, se continuará con el plan de tratamiento previamente establecido, realizando las modificaciones necesarias para atender los requerimientos de la persona y considerando los factores que hayan podido incidir en el abandono. Con todo, respecto de una persona que ha abandonado la hospitalización psiquiátrica involuntaria sin el consentimiento del equipo tratante, no se podrá reanudar la hospitalización, en un establecimiento o unidad de hospitalización psiquiátrica, más allá de los quince días corridos siguientes a su salida no consensuada sin que se le haya sometido a una nueva evaluación por un médico psiquiatra. Lo establecido en el inciso anterior no se aplicará a aquellas personas hospitalizadas por orden de la autoridad judicial y que se encuentran sometidas aún a su control y resguardo. 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 16/22", "notes": []}], "observaciones_general": ""}]}, {"id": "ninos-adolescentes", "name": "Niños, Niñas y Adolescentes", "ambitos": [{"id": "hp_ninos-adolescentes__art78", "tipo": "ARTÍCULO", "name": "Artículo 78 · De la segregación respecto de adultos hospitalizados", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 78, "text": "Las hospitalizaciones de niños, niñas y adolescentes deberán ser realizadas principalmente en establecimientos de salud o unidades de hospitalización en psiquiatría especializadas en población infanto adolescente. Solo en aquellos territorios que este servicio no esté disponible se deberán evaluar alternativas disponibles, para evitar la hospitalización de niños, niñas y adolescentes en servicios dispuestos para población adulta. Alternativamente, será posible hospitalizar a los niños, niñas y adolescentes transitoriamente en servicios de pediatría con apoyo de especialistas en psiquiatría, en servicios de hospitalización psiquiátrica infanto adolescente de otros servicios de salud o recurriendo a servicios de carácter privado.", "notes": []}], "observaciones_general": ""}, {"id": "hp_ninos-adolescentes__art80", "tipo": "ARTÍCULO", "name": "Artículo 80 · Del derecho a compañía", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 80, "text": "Los reglamentos internos de los establecimientos deberán permitir la compañía de su padre, madre, cuidador/a o persona significativa en todo momento, salvo que el equipo considere que ello pueda generar un riesgo para la persona en tratamiento o para otros usuarios del establecimiento.", "notes": []}], "observaciones_general": ""}, {"id": "hp_ninos-adolescentes__art82__header", "tipo": "ARTÍCULO", "name": "Artículo 82 · De la hospitalización psiquiátrica como medida de protección", "notes_in_title": [], "objetivo": "En caso de que la persona adulta responsable no sea encontrada, se niegue a autorizar una prestación necesaria o actúe de forma negligente respecto de los cuidados del niño, niña o adolescente, y se estime necesaria la hospitalización psiquiátrica involuntaria del niño, niña o adolescente, se podrá solicitar al Tribunal de Familia competente la medida de protección indicada en el literal", "notes_in_objetivo": [], "requisitos": [{"n": "82.h", "text": "del artículo 71 de la ley N° 19.968, que crea los Tribunales de Familia. Esta medida dispone la internación en un establecimiento hospitalario, psiquiátrico o de tratamiento especializado, según corresponda, en la medida que se requiera de los servicios que éstos ofrecen y ello sea indispensable frente a una amenaza de la vida o salud.", "notes": []}], "observaciones_general": ""}, {"id": "hp_ninos-adolescentes__art83", "tipo": "ARTÍCULO", "name": "Artículo 83 · De la revisión por Tribunales de Familia", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 83, "text": "Si transcurridas setenta y dos horas desde el inicio de la hospitalización involuntaria se mantienen todas las condiciones que la hicieron procedente y se estima necesario prolongarla, la autoridad sanitaria solicitará su revisión al Tribunal de Familia competente del lugar donde se encuentre el establecimiento de salud respectivo. En este proceso, se entregará al Tribunal todos los antecedentes necesarios para analizar el caso, incluyendo un informe del equipo médico tratante que justifique la prolongación de la hospitalización involuntaria. El Tribunal de Familia respectivo, en el plazo de tres días hábiles contado desde la presentación de la solicitud, deberá resolver si se cumple con los requisitos de legalidad establecidos en el artículo 13 de la ley N° 21.331 y del artículo 40 de este reglamento. En caso de ser necesario, el Tribunal de Familia podrá, dentro del plazo de tres días hábiles, oficiar, solicitando informes complementarios a los y las profesionales tratantes y a la Comisión Regional de Protección de los Derechos de las Personas con Enfermedades Mentales. Dichos informes deberán ser entregados al Tribunal en el plazo de cinco días hábiles. Corresponderá al Servicio de Salud respectivo tramitar dichos oficios. Transcurridos los plazos señalados anteriormente, según corresponda, y en caso de no cumplirse con los requisitos de legalidad establecidos en el artículo 13 de la ley N° 21.331 y el artículo 40 de este reglamento, el Juez de Familia correspondiente deberá ordenar la cesación de la hospitalización psiquiátrica involuntaria. Cada treinta días corridos, contados desde la última revisión por parte del Juez de Familia respectivo, y siempre que el equipo médico estime que es necesario prolongarla, se deberá enviar al Tribunal una actualización de los antecedentes señalados en el inciso primero. Esta actualización debe reflejar la evolución de la persona hospitalizada y deberá ser enviada dentro de las veinticuatro horas siguientes al cumplimiento de dicho plazo. La Secretaría Regional Ministerial de Salud correspondiente deberá mantenerse informada de estas comunicaciones. Para ello, toda información enviada al Tribunal de Familia deberá ser ingresada en la plataforma de información en línea que el Ministerio de Salud disponga para este propósito, con la finalidad de dar seguimiento al caso. La comunicación con el Tribunal de Familia se hará preferentemente a través de la plataforma informática del Poder judicial. En cualquier momento, la o el juez de familia podrá disponer el alta hospitalaria inmediata si es que no se cumplen los requisitos legales contemplados en el artículo 13 de la ley N° 21.331 y el artículo 40 de este reglamento.", "notes": []}], "observaciones_general": ""}, {"id": "hp_ninos-adolescentes__art84", "tipo": "ARTÍCULO", "name": "Artículo 84 · De la designación de abogado o abogada", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 84, "text": "La persona hospitalizada involuntariamente o su representante legal tendrán derecho a designar uno o más abogados o abogadas de su confianza. Si no lo tuviere, el Tribunal de Familia competente podrá designar uno por el o la persona hospitalizada. En cualquier caso, la designación del abogado o abogada deberá tener lugar antes de la realización de la primera audiencia a que fuere citada la persona hospitalizada involuntariamente. 6/5/26, 12:27 Ley Chile - Decreto 9 03-OCT-2025 MINISTERIO DE SALUD, SUBSECRETARÍA DE SALUD PÚBLICA - Biblioteca del Congreso Naci… https://www.bcn.cl/leychile/navegar/imprimir?idNorma=1217190&idVersion=2025-12-02 18/22 Para estos efectos, será competente el Tribunal de Familia del lugar en donde la persona hospitalizada involuntariamente se encontrare. En caso de que sea necesaria la comparecencia personal de la persona hospitalizada, se facilitarán los mismos mecanismos de traslado que se utilizaron para efectuar la hospitalización.", "notes": []}], "observaciones_general": ""}]}, {"id": "comunicacion", "name": "Comunicación de Vulneraciones", "ambitos": [{"id": "hp_comunicacion__art95", "tipo": "ARTÍCULO", "name": "Artículo 95 · Del deber de comunicar vulneraciones de derechos", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": 95, "text": "Con el fin de garantizar los derechos humanos de las personas con enfermedad mental o trastorno mental, los y las integrantes profesionales y no profesionales del equipo de salud serán responsables de informar a la Secretaría Regional Ministerial de Salud y a la Comisión Regional de Protección de los Derechos de las Personas con Enfermedades Mentales sobre cualquier sospecha de irregularidad que implique un trato indigno o inhumano a personas bajo tratamiento o una limitación indebida de su autonomía. El funcionario o funcionaria podrá actuar bajo reserva de identidad y no se considerará que ha incurrido en violación del secreto profesional. La sola comunicación a un superior jerárquico dentro de la institución no releva al equipo de salud de tal responsabilidad si la situación irregular persiste.", "notes": []}], "observaciones_general": ""}, {"id": "hp_comunicacion__art96__header", "tipo": "ARTÍCULO", "name": "Artículo 96 · De la denuncia obligatoria", "notes_in_title": [], "objetivo": "Sin perjuicio de lo dispuesto en el artículo precedente, en caso de sospecha de delito, se deberá dar cumplimiento al deber de denuncia conforme lo dispuesto en el literal", "notes_in_objetivo": [], "requisitos": [{"n": "96.d", "text": "y", "notes": []}, {"n": "96.f", "text": "del artículo 175 del Código Procesal Penal, que establece la obligación de denuncia de los jefes de establecimientos hospitalarios o de clínicas particulares y, en general, los profesionales en medicina, odontología, química, farmacia y de otras ramas relacionadas con la conservación o el restablecimiento de la salud, y los que ejercieren prestaciones auxiliares de ellas, que notaren en una persona o en un cadáver señales de envenenamiento o de otro delito; así como los jefes de establecimientos de salud, públicos o privados, respecto de los delitos perpetrados contra los profesionales y funcionarios de dichos establecimientos al interior de sus dependencias o mientras éstos se encontraren en el ejercicio de sus funciones o en razón, con motivo u ocasión de ellas. Las personas indicadas en el artículo anterior deberán hacer la denuncia dentro de las veinticuatro horas siguientes al momento en que tomaren conocimiento del hecho que reviste características, de acuerdo a lo señalado en el artículo 176 del Código Procesal Penal.", "notes": []}], "observaciones_general": ""}]}, {"id": "uhcip-materiales", "name": "Infraestructura UHCIP · Materiales y Elementos Constructivos", "ambitos": [{"id": "hp_uhcip-materiales__pavimentos", "tipo": "INFRAESTRUCTURA", "name": "Pavimentos", "notes_in_title": [], "objetivo": "Material recomendado: Baldosa micro vibrada / Loza afinada / PVC continuo de alto tránsito", "notes_in_objetivo": [], "requisitos": [{"n": "pavimentos.1", "text": "El pavimento es ignífugo (no combustible).", "notes": []}, {"n": "pavimentos.2", "text": "El pavimento es monolítico: no desmontable ni desarmable.", "notes": []}, {"n": "pavimentos.3", "text": "El pavimento es impermeable.", "notes": []}, {"n": "pavimentos.4", "text": "El pavimento es antideslizante.", "notes": []}, {"n": "pavimentos.5", "text": "El material corresponde a baldosa micro vibrada, loza afinada o PVC continuo de alto tránsito.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__muros-perimetrales", "tipo": "INFRAESTRUCTURA", "name": "Muros perimetrales del edificio", "notes_in_title": [], "objetivo": "Material recomendado: Hormigón", "notes_in_objetivo": [], "requisitos": [{"n": "muros-perimetrales.1", "text": "Los muros perimetrales son ignífugos (no combustibles).", "notes": []}, {"n": "muros-perimetrales.2", "text": "Son resistentes a golpes / al impacto.", "notes": []}, {"n": "muros-perimetrales.3", "text": "Son anti vandálicos: no horadables ni perforables (se excluyen placas de madera, yeso cartón, albañilería o fibrocemento).", "notes": []}, {"n": "muros-perimetrales.4", "text": "El material corresponde a hormigón.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__muros-interiores", "tipo": "INFRAESTRUCTURA", "name": "Muros y tabiques interiores", "notes_in_title": [], "objetivo": "Material recomendado: Hormigón / Fibrocemento de 8 mm / Antivandálicos", "notes_in_objetivo": [], "requisitos": [{"n": "muros-interiores.1", "text": "Son ignífugos (no combustibles).", "notes": []}, {"n": "muros-interiores.2", "text": "Son resistentes a golpes / al impacto, evitando que el paciente extraiga material para auto-inferirse heridas o herir a terceros.", "notes": []}, {"n": "muros-interiores.3", "text": "Son de material anti vandálico.", "notes": []}, {"n": "muros-interiores.4", "text": "El material corresponde a hormigón, fibrocemento de 8 mm o solución antivandálica.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__guardapolvos", "tipo": "INFRAESTRUCTURA", "name": "Guardapolvos o cornisas", "notes_in_title": [], "objetivo": "Material recomendado: No se consideran", "notes_in_objetivo": [], "requisitos": [{"n": "guardapolvos.1", "text": "No se consideran guardapolvos ni cornisas de ningún material (metálico, PVC, poliestireno o madera), por ser elementos extraíbles transformables en arma de auto-agresión o agresión a terceros.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__cielos", "tipo": "INFRAESTRUCTURA", "name": "Cielos", "notes_in_title": [], "objetivo": "Material recomendado: Losa de hormigón", "notes_in_objetivo": [], "requisitos": [{"n": "cielos.1", "text": "El cielo es ignífugo (no combustible).", "notes": []}, {"n": "cielos.2", "text": "Es resistente a golpes.", "notes": []}, {"n": "cielos.3", "text": "No es desmontable (absolutamente anti vandálico).", "notes": []}, {"n": "cielos.4", "text": "Se excluyen cielos de placa o cielos falsos de volcanita o poliestireno.", "notes": []}, {"n": "cielos.5", "text": "El material corresponde a losa de hormigón.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__puertas", "tipo": "INFRAESTRUCTURA", "name": "Puertas (principales, multipropósito, comedor, estar, hospitalización, box, baños)", "notes_in_title": [], "objetivo": "Material recomendado: Madera anti vandálica", "notes_in_objetivo": [], "requisitos": [{"n": "puertas.1", "text": "Las puertas impiden ser extraídas / desmontadas.", "notes": []}, {"n": "puertas.2", "text": "Son de alta resistencia al impacto: revestimiento de vinil acrílico de alto impacto y densidad, resistente a altas temperaturas, o pintura ignífuga (anti vandálicas).", "notes": []}, {"n": "puertas.3", "text": "Las superficies traslúcidas o transparentes son de vidrio blindado con film por ambas caras, o policarbonato de 8 mm; queda excluido el vidrio simple.", "notes": []}, {"n": "puertas.4", "text": "Todas las puertas abren hacia el exterior del recinto, para acceder en caso de emergencia.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__puertas-evacuacion", "tipo": "INFRAESTRUCTURA", "name": "Puertas de evacuación", "notes_in_title": [], "objetivo": "Material recomendado: Metálicas", "notes_in_objetivo": [], "requisitos": [{"n": "puertas-evacuacion.1", "text": "Las puertas de evacuación son metálicas.", "notes": []}, {"n": "puertas-evacuacion.2", "text": "Su ubicación queda a resguardo y control de los encargados y funcionarios de la unidad, y alejadas de las áreas de trabajo terapéutico.", "notes": []}, {"n": "puertas-evacuacion.3", "text": "Cumplen las especificaciones del fabricante (estándar).", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__marcos", "tipo": "INFRAESTRUCTURA", "name": "Marcos de puertas", "notes_in_title": [], "objetivo": "Material recomendado: Acero / Aluminio", "notes_in_objetivo": [], "requisitos": [{"n": "marcos.1", "text": "Los marcos son metálicos (acero o aluminio).", "notes": []}, {"n": "marcos.2", "text": "Están fijados a muro de hormigón.", "notes": []}, {"n": "marcos.3", "text": "Son anti vandálicos.", "notes": []}, {"n": "marcos.4", "text": "Son de vaivén o de instalación normal.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__cerraduras", "tipo": "INFRAESTRUCTURA", "name": "Cerraduras de puertas", "notes_in_title": [], "objetivo": "Material recomendado: Embutidas de seguridad", "notes_in_objetivo": [], "requisitos": [{"n": "cerraduras.1", "text": "Las cerraduras son embutidas de seguridad.", "notes": []}, {"n": "cerraduras.2", "text": "No se consideran cerraduras sobrepuestas.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__ventanas", "tipo": "INFRAESTRUCTURA", "name": "Ventanas, protecciones y vidrios", "notes_in_title": [], "objetivo": "Material recomendado: Metálica / Con protección", "notes_in_objetivo": [], "requisitos": [{"n": "ventanas.1", "text": "Los marcos de ventana son metálicos, fijados a muro.", "notes": []}, {"n": "ventanas.2", "text": "Toda protección va por el exterior del edificio y fijada a muro perimetral de manera vertical.", "notes": []}, {"n": "ventanas.3", "text": "Las dimensiones de la abertura de las ventanas no superan los 30 cm.", "notes": []}, {"n": "ventanas.4", "text": "Las ventanas con apertura (en box / unidades) abren hacia patios interiores de la unidad.", "notes": []}, {"n": "ventanas.5", "text": "Los vidrios son laminados, templados o inastillables; en su defecto policarbonato monolítico de 6 mm. Se descarta el vidrio simple.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__sanitarios", "tipo": "INFRAESTRUCTURA", "name": "Artefactos sanitarios", "notes_in_title": [], "objetivo": "Material recomendado: Anti vandálicos / Acero inoxidable / Acero o resina", "notes_in_objetivo": [], "requisitos": [{"n": "sanitarios.1", "text": "Los artefactos sanitarios son anti vandálicos.", "notes": []}, {"n": "sanitarios.2", "text": "Son de alta resistencia al impacto e incombustibles.", "notes": []}, {"n": "sanitarios.3", "text": "El WC y los lavamanos son de acero inoxidable, acero o resina.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__accesorios-bano", "tipo": "INFRAESTRUCTURA", "name": "Portarollos, jaboneras, espejos y cortinas", "notes_in_title": [], "objetivo": "Material recomendado: De PVC / Acero inoxidable", "notes_in_objetivo": [], "requisitos": [{"n": "accesorios-bano.1", "text": "Todos los accesorios de baño son anti vandálicos.", "notes": []}, {"n": "accesorios-bano.2", "text": "Los espejos son de acero inoxidable brillante (calibre 20).", "notes": []}, {"n": "accesorios-bano.3", "text": "El portarollo es de PVC y se instala fuera de la cabina del WC.", "notes": []}, {"n": "accesorios-bano.4", "text": "Las cortinas de ducha van sujetas directamente al cielo y ceden ante una resistencia mínima.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__revestimiento-bano", "tipo": "INFRAESTRUCTURA", "name": "Revestimiento en baños", "notes_in_title": [], "objetivo": "Material recomendado: Pintura sintética / Esmalte al agua", "notes_in_objetivo": [], "requisitos": [{"n": "revestimiento-bano.1", "text": "No se instalan cerámicas (baja resistencia al impacto).", "notes": []}, {"n": "revestimiento-bano.2", "text": "El revestimiento es pintura sintética o esmalte al agua.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__celosias", "tipo": "INFRAESTRUCTURA", "name": "Celosías de ventilación", "notes_in_title": [], "objetivo": "Material recomendado: Acero inoxidable / Tornillos inviolables", "notes_in_objetivo": [], "requisitos": [{"n": "celosias.1", "text": "Las celosías están afianzadas con tornillos inviolables.", "notes": []}, {"n": "celosias.2", "text": "Son de acero inoxidable.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-materiales__pinturas", "tipo": "INFRAESTRUCTURA", "name": "Pinturas", "notes_in_title": [], "objetivo": "Material recomendado: Sintéticos / Esmalte al agua", "notes_in_objetivo": [], "requisitos": [{"n": "pinturas.1", "text": "Las pinturas son sintéticas o esmalte al agua.", "notes": []}], "observaciones_general": ""}]}, {"id": "uhcip-mobiliario", "name": "Infraestructura UHCIP · Mobiliario y Techumbres", "ambitos": [{"id": "hp_uhcip-mobiliario__mob-exterior", "tipo": "INFRAESTRUCTURA", "name": "Mobiliario urbano o exterior", "notes_in_title": [], "objetivo": "Material recomendado: Hormigón granítico / Hormigón visto / Metálico", "notes_in_objetivo": [], "requisitos": [{"n": "mob-exterior.1", "text": "Todo el mobiliario está afianzado o fijado a la superficie de piso o muro (inamovible).", "notes": []}, {"n": "mob-exterior.2", "text": "Sus características impiden su manipulación o deformación.", "notes": []}, {"n": "mob-exterior.3", "text": "Es resistente, de alto impacto a golpes e ignífugo.", "notes": []}, {"n": "mob-exterior.4", "text": "El material corresponde a hormigón granítico, hormigón visto o metálico.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-mobiliario__mob-interior", "tipo": "INFRAESTRUCTURA", "name": "Mobiliario interior aéreo", "notes_in_title": [], "objetivo": "Material recomendado: Fijado a muro de hormigón / a estructura de tabique / Ignífugo", "notes_in_objetivo": [], "requisitos": [{"n": "mob-interior.1", "text": "El mobiliario de almacenamiento de insumos clínicos, instrumental y fármacos cuenta con cerradura con llave.", "notes": []}, {"n": "mob-interior.2", "text": "Está fijado a muros de hormigón o a estructura de tabique.", "notes": []}, {"n": "mob-interior.3", "text": "Es ignífugo.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-mobiliario__camas", "tipo": "INFRAESTRUCTURA", "name": "Camas", "notes_in_title": [], "objetivo": "Material recomendado: Hormigón / Metálicas", "notes_in_objetivo": [], "requisitos": [{"n": "camas.1", "text": "Las camas permiten abordar al paciente desde sus 3 costados.", "notes": []}, {"n": "camas.2", "text": "Son de material ignífugo (hormigón o metálicas).", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-mobiliario__closet", "tipo": "INFRAESTRUCTURA", "name": "Closet", "notes_in_title": [], "objetivo": "Material recomendado: Hormigón (obra)", "notes_in_objetivo": [], "requisitos": [{"n": "closet.1", "text": "En el dormitorio se considera closet de obra (hormigón) con repisas.", "notes": []}, {"n": "closet.2", "text": "Las puertas son sin manillas, solo con un sacado en su borde.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-mobiliario__casilleros", "tipo": "INFRAESTRUCTURA", "name": "Casilleros", "notes_in_title": [], "objetivo": "Material recomendado: Hormigón (obra)", "notes_in_objetivo": [], "requisitos": [{"n": "casilleros.1", "text": "Los casilleros son de obra.", "notes": []}, {"n": "casilleros.2", "text": "Los medios casilleros tienen chapa con sistema de moneda u otro que cumpla normas de seguridad.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-mobiliario__techumbres", "tipo": "INFRAESTRUCTURA", "name": "Techumbres", "notes_in_title": [], "objetivo": "Material recomendado: Planchas de acero", "notes_in_objetivo": [], "requisitos": [{"n": "techumbres.1", "text": "Las techumbres son de planchas de acero.", "notes": []}], "observaciones_general": ""}]}, {"id": "uhcip-instalaciones", "name": "Infraestructura UHCIP · Instalaciones y Seguridad", "ambitos": [{"id": "hp_uhcip-instalaciones__griferias", "tipo": "INFRAESTRUCTURA", "name": "Griferías", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": "griferias.1", "text": "Las griferías son anti vandálicas.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__llaves-paso", "tipo": "INFRAESTRUCTURA", "name": "Llaves de paso", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": "llaves-paso.1", "text": "Existe llave de paso para cada recinto.", "notes": []}, {"n": "llaves-paso.2", "text": "Las llaves de paso son controladas por el personal desde fuera del recinto que atiende.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__piletas", "tipo": "INFRAESTRUCTURA", "name": "Piletas y desagües de baño", "notes_in_title": [], "objetivo": "Material recomendado: Plancha de acero inoxidable 5 mm", "notes_in_objetivo": [], "requisitos": [{"n": "piletas.1", "text": "La pileta considera rejilla de protección de plancha de acero inoxidable de 5 mm de espesor.", "notes": []}, {"n": "piletas.2", "text": "La rejilla está afianzada con tornillos inviolables o es anti vandálica.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__climatizacion", "tipo": "INFRAESTRUCTURA", "name": "Climatización", "notes_in_title": [], "objetivo": "Material recomendado: Embutida en cielo", "notes_in_objetivo": [], "requisitos": [{"n": "climatizacion.1", "text": "La climatización es embutida en el cielo.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__electricas", "tipo": "INFRAESTRUCTURA", "name": "Instalaciones eléctricas", "notes_in_title": [], "objetivo": "Material recomendado: Embutidas", "notes_in_objetivo": [], "requisitos": [{"n": "electricas.1", "text": "No se consideran enchufes en dormitorios.", "notes": []}, {"n": "electricas.2", "text": "Las instalaciones eléctricas son todas embutidas.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__telefonos", "tipo": "INFRAESTRUCTURA", "name": "Teléfonos", "notes_in_title": [], "objetivo": "Material recomendado: Acero inoxidable calibre pesado", "notes_in_objetivo": [], "requisitos": [{"n": "telefonos.1", "text": "De existir teléfono para uso de pacientes, está ubicado en la estación de enfermería.", "notes": []}, {"n": "telefonos.2", "text": "Tiene panel de acero inoxidable de calibre pesado, teclado de tonos táctil de metal, cable blindado y auricular de servicio pesado.", "notes": []}, {"n": "telefonos.3", "text": "Transmisor y receptor con conexiones selladas, conectores de tope rellenos de gel y placa de circuito sellada.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__televisor", "tipo": "INFRAESTRUCTURA", "name": "Televisor", "notes_in_title": [], "objetivo": "Material recomendado: Empotrado / Policarbonato", "notes_in_objetivo": [], "requisitos": [{"n": "televisor.1", "text": "El televisor está fijado a una altura suficiente que impide su extracción.", "notes": []}, {"n": "televisor.2", "text": "Cuenta con placa de protección de policarbonato traslúcido o, en su defecto, está embutido a muro.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__luminarias", "tipo": "INFRAESTRUCTURA", "name": "Luminarias", "notes_in_title": [], "objetivo": "Material recomendado: Embutidas", "notes_in_objetivo": [], "requisitos": [{"n": "luminarias.1", "text": "Las luminarias son embutidas.", "notes": []}, {"n": "luminarias.2", "text": "Las luminarias son anti vandálicas.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__camaras-recintos", "tipo": "INFRAESTRUCTURA", "name": "Tecnovigilancia / cámaras en recintos de pacientes", "notes_in_title": [], "objetivo": "Material recomendado: Espejo panorámico de seguridad", "notes_in_objetivo": [], "requisitos": [{"n": "camaras-recintos.1", "text": "En los recintos de pacientes NO se instalan cámaras, para resguardar sus derechos.", "notes": []}, {"n": "camaras-recintos.2", "text": "Se considera un espejo panorámico de seguridad (tipo estacionamiento) de acero inoxidable.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__cctv-publicas", "tipo": "INFRAESTRUCTURA", "name": "CCTV en áreas públicas, TEC y cuidados especiales", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": "cctv-publicas.1", "text": "Las áreas públicas (estares, circulaciones y patios) cuentan con vigilancia y monitoreo por CCTV conectado a central de monitoreo.", "notes": []}, {"n": "cctv-publicas.2", "text": "Las áreas de terapia electroconvulsiva (TEC) y de cuidados especiales cuentan con CCTV.", "notes": []}, {"n": "cctv-publicas.3", "text": "El uso de cámaras se gestiona conforme a la Ley de deberes y derechos en materia de consentimiento de pacientes o sus tutores.", "notes": []}, {"n": "cctv-publicas.4", "text": "Las grabaciones se conservan por 7 días, para responder a una eventual judicialización.", "notes": []}], "observaciones_general": "Distinguir: en recintos de pacientes NO se instalan cámaras (usar espejo panorámico); en áreas públicas, TEC y cuidados especiales SÍ se exige CCTV."}, {"id": "hp_uhcip-instalaciones__red-humeda-seca", "tipo": "INFRAESTRUCTURA", "name": "Red húmeda y seca", "notes_in_title": [], "objetivo": "Material recomendado: Gabinetes en zonas restringidas", "notes_in_objetivo": [], "requisitos": [{"n": "red-humeda-seca.1", "text": "Los gabinetes de red húmeda y seca se ubican en zonas restringidas a las personas hospitalizadas.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__extintores", "tipo": "INFRAESTRUCTURA", "name": "Extintores", "notes_in_title": [], "objetivo": "Material recomendado: Gabinetes de PVC con cierre plástico", "notes_in_objetivo": [], "requisitos": [{"n": "extintores.1", "text": "Los extintores están en gabinetes de PVC con sistema de cierre plástico.", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__aguas-lluvias", "tipo": "INFRAESTRUCTURA", "name": "Bajadas de aguas lluvias", "notes_in_title": [], "objetivo": "", "notes_in_objetivo": [], "requisitos": [{"n": "aguas-lluvias.1", "text": "No se consideran bajadas de aguas lluvias en patios de unidades de salud mental infanto-adolescente (evitar elementos escalables / de auto-agresión).", "notes": []}], "observaciones_general": ""}, {"id": "hp_uhcip-instalaciones__quincalleria", "tipo": "INFRAESTRUCTURA", "name": "Quincallería y apertura de puertas (seguridad)", "notes_in_title": [], "objetivo": "Material recomendado: Cerrojos de seguridad / Tiradores bajo relieve", "notes_in_objetivo": [], "requisitos": [{"n": "quincalleria.1", "text": "Todas las puertas de los recintos abren hacia afuera, para evitar que los pacientes se bloqueen o encierren.", "notes": []}, {"n": "quincalleria.2", "text": "Las aperturas se resguardan para no perturbar la circulación.", "notes": []}, {"n": "quincalleria.3", "text": "La quincallería usa cerrojos de seguridad y tiradores bajo relieve, evitando elementos utilizables para auto-agresión.", "notes": []}], "observaciones_general": ""}]}], "notas_al_pie": {}};
